const REGIONS = [10000002, 10000043, 10000032, 10000030, 10000042];
const rows = [];
for (const item of $input.all()) {
  const typeId = item.json.type_id;
  for (const regionId of REGIONS) {
    try {
      const hist = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://esi.evetech.net/latest/markets/${regionId}/history/`,
        qs: { datasource: 'tranquility', type_id: typeId },
        json: true
      });
      for (const d of hist.slice(-90)) {
        rows.push({ json: { type_id: typeId, region_id: regionId,
          date: d.date, average: d.average, volume: d.volume, order_count: d.order_count } });
      }
    } catch (e) { /* нет истории — пропускаем */ }
  }
}
return rows;
